/**
 * New Supplier Form Page
 * Creates a new supplier record via POST /api/accounting/suppliers-list.
 * Route: /accounting/suppliers/new
 */

import { useState } from 'react';
import { useRouter } from 'next/router';
import { AppLayout } from '@/components/layout/AppLayout';
import { Truck, Loader2, ArrowLeft, Save } from 'lucide-react';
import Link from 'next/link';
import { toast } from 'react-hot-toast';

interface SupplierFormData {
  name: string;
  company_name: string;
  email: string;
  phone: string;
  vat_number: string;
  registration_number: string;
  contact_person: string;
  payment_terms: string;
  address: string;
  category: string;
  notes: string;
  is_active: boolean;
  // Bank details
  bank_name: string;
  bank_account_number: string;
  bank_branch_code: string;
  bank_account_type: string;
}

const INITIAL_FORM: SupplierFormData = {
  name: '',
  company_name: '',
  email: '',
  phone: '',
  vat_number: '',
  registration_number: '',
  contact_person: '',
  payment_terms: '30',
  address: '',
  category: '',
  notes: '',
  is_active: true,
  bank_name: '',
  bank_account_number: '',
  bank_branch_code: '',
  bank_account_type: 'current',
};

const ACCOUNT_TYPES = [
  { value: 'current', label: 'Current / Cheque' },
  { value: 'savings', label: 'Savings' },
  { value: 'transmission', label: 'Transmission' },
];

const SUPPLIER_CATEGORIES = [
  'Materials',
  'Services',
  'Equipment',
  'Subcontractor',
  'Utilities',
  'Professional Services',
  'Logistics',
  'Other',
];

interface FieldProps {
  label: string;
  required?: boolean;
  children: React.ReactNode;
  hint?: string;
}

function Field({ label, required, children, hint }: FieldProps) {
  return (
    <div>
      <label className="block text-sm font-medium text-[var(--ff-text-secondary)] mb-1">
        {label}
        {required && <span className="text-red-400 ml-1">*</span>}
      </label>
      {children}
      {hint && <p className="mt-1 text-xs text-[var(--ff-text-tertiary)]">{hint}</p>}
    </div>
  );
}

const inputClass =
  'w-full px-3 py-2 rounded-lg bg-[var(--ff-bg-tertiary)] border border-[var(--ff-border-primary)] text-[var(--ff-text-primary)] placeholder:text-[var(--ff-text-tertiary)] text-sm focus:outline-none focus:ring-1 focus:ring-emerald-500';

const textareaClass = `${inputClass} resize-none`;
const selectClass = `${inputClass} cursor-pointer`;

export default function NewSupplierPage() {
  const router = useRouter();
  const [form, setForm] = useState<SupplierFormData>(INITIAL_FORM);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [fieldErrors, setFieldErrors] = useState<Partial<Record<keyof SupplierFormData, string>>>({});

  function set<K extends keyof SupplierFormData>(key: K, value: SupplierFormData[K]) {
    setForm((prev) => ({ ...prev, [key]: value }));
    setFieldErrors((prev) => ({ ...prev, [key]: undefined }));
  }

  function validate(): boolean {
    const errors: Partial<Record<keyof SupplierFormData, string>> = {};
    if (!form.name.trim()) errors.name = 'Supplier name is required';
    if (form.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) {
      errors.email = 'Enter a valid email address';
    }
    if (form.payment_terms && isNaN(Number(form.payment_terms))) {
      errors.payment_terms = 'Must be a number';
    }
    setFieldErrors(errors);
    return Object.keys(errors).length === 0;
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!validate()) return;

    setIsSubmitting(true);
    try {
      const payload = {
        ...form,
        payment_terms: form.payment_terms ? Number(form.payment_terms) : 30,
        // Clear empty bank fields to avoid storing blank strings
        bank_name: form.bank_name.trim() || null,
        bank_account_number: form.bank_account_number.trim() || null,
        bank_branch_code: form.bank_branch_code.trim() || null,
        bank_account_type: form.bank_account_type || null,
      };

      const res = await fetch('/api/accounting/suppliers-list', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      const json = await res.json();

      if (!res.ok) {
        throw new Error(json.error?.message ?? `HTTP ${res.status}`);
      }

      toast.success('Supplier created successfully');
      await router.push('/accounting/suppliers');
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Failed to create supplier';
      toast.error(message);
    } finally {
      setIsSubmitting(false);
    }
  }

  return (
    <AppLayout>
      <div className="min-h-screen bg-[var(--ff-bg-primary)]">
        {/* Header */}
        <div className="border-b border-[var(--ff-border-primary)] bg-[var(--ff-bg-secondary)]">
          <div className="px-6 py-4 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <Link
                href="/accounting/suppliers"
                className="p-1.5 rounded-lg hover:bg-[var(--ff-bg-tertiary)] text-[var(--ff-text-secondary)] transition-colors"
              >
                <ArrowLeft className="h-5 w-5" />
              </Link>
              <div className="p-2 rounded-lg bg-blue-500/10">
                <Truck className="h-6 w-6 text-blue-500" />
              </div>
              <div>
                <h1 className="text-xl font-semibold text-[var(--ff-text-primary)]">New Supplier</h1>
                <p className="text-sm text-[var(--ff-text-secondary)]">Add a new supplier account</p>
              </div>
            </div>
          </div>
        </div>

        <div className="p-6 max-w-3xl">
          <form onSubmit={handleSubmit} noValidate>
            {/* Basic Information */}
            <div className="rounded-lg border border-[var(--ff-border-primary)] bg-[var(--ff-surface-primary)] p-6 mb-6">
              <h2 className="text-sm font-semibold text-[var(--ff-text-primary)] uppercase tracking-wide mb-4">
                Basic Information
              </h2>
              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
                <Field label="Supplier Name" required>
                  <input
                    type="text"
                    value={form.name}
                    onChange={(e) => set('name', e.target.value)}
                    placeholder="e.g. ABC Supplies (Pty) Ltd"
                    className={inputClass}
                    autoFocus
                  />
                  {fieldErrors.name && (
                    <p className="mt-1 text-xs text-red-400">{fieldErrors.name}</p>
                  )}
                </Field>

                <Field label="Company / Trading Name" hint="If different from supplier name">
                  <input
                    type="text"
                    value={form.company_name}
                    onChange={(e) => set('company_name', e.target.value)}
                    placeholder="Trading name"
                    className={inputClass}
                  />
                </Field>

                <Field label="Email Address">
                  <input
                    type="email"
                    value={form.email}
                    onChange={(e) => set('email', e.target.value)}
                    placeholder="accounts@supplier.com"
                    className={inputClass}
                  />
                  {fieldErrors.email && (
                    <p className="mt-1 text-xs text-red-400">{fieldErrors.email}</p>
                  )}
                </Field>

                <Field label="Phone Number">
                  <input
                    type="tel"
                    value={form.phone}
                    onChange={(e) => set('phone', e.target.value)}
                    placeholder="+27 11 000 0000"
                    className={inputClass}
                  />
                </Field>

                <Field label="Contact Person">
                  <input
                    type="text"
                    value={form.contact_person}
                    onChange={(e) => set('contact_person', e.target.value)}
                    placeholder="Jane Doe"
                    className={inputClass}
                  />
                </Field>

                <Field label="Category">
                  <select
                    value={form.category}
                    onChange={(e) => set('category', e.target.value)}
                    className={selectClass}
                  >
                    <option value="">Select category...</option>
                    {SUPPLIER_CATEGORIES.map((cat) => (
                      <option key={cat} value={cat}>{cat}</option>
                    ))}
                  </select>
                </Field>

                <Field label="VAT Number">
                  <input
                    type="text"
                    value={form.vat_number}
                    onChange={(e) => set('vat_number', e.target.value)}
                    placeholder="4123456789"
                    className={inputClass}
                  />
                </Field>

                <Field label="Registration Number">
                  <input
                    type="text"
                    value={form.registration_number}
                    onChange={(e) => set('registration_number', e.target.value)}
                    placeholder="2020/123456/07"
                    className={inputClass}
                  />
                </Field>

                <Field label="Payment Terms" hint="Days until payment is due">
                  <input
                    type="number"
                    min="0"
                    value={form.payment_terms}
                    onChange={(e) => set('payment_terms', e.target.value)}
                    className={inputClass}
                  />
                  {fieldErrors.payment_terms && (
                    <p className="mt-1 text-xs text-red-400">{fieldErrors.payment_terms}</p>
                  )}
                </Field>

                <div className="sm:col-span-2">
                  <Field label="Physical Address">
                    <textarea
                      value={form.address}
                      onChange={(e) => set('address', e.target.value)}
                      rows={3}
                      placeholder="Street address, city, postal code"
                      className={textareaClass}
                    />
                  </Field>
                </div>
              </div>
            </div>

            {/* Bank Details */}
            <div className="rounded-lg border border-[var(--ff-border-primary)] bg-[var(--ff-surface-primary)] p-6 mb-6">
              <h2 className="text-sm font-semibold text-[var(--ff-text-primary)] uppercase tracking-wide mb-1">
                Bank Details
              </h2>
              <p className="text-xs text-[var(--ff-text-tertiary)] mb-4">
                Required for EFT payments and batch payment runs
              </p>
              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
                <Field label="Bank Name">
                  <input
                    type="text"
                    value={form.bank_name}
                    onChange={(e) => set('bank_name', e.target.value)}
                    placeholder="e.g. First National Bank"
                    className={inputClass}
                  />
                </Field>

                <Field label="Account Type">
                  <select
                    value={form.bank_account_type}
                    onChange={(e) => set('bank_account_type', e.target.value)}
                    className={selectClass}
                  >
                    {ACCOUNT_TYPES.map((t) => (
                      <option key={t.value} value={t.value}>{t.label}</option>
                    ))}
                  </select>
                </Field>

                <Field label="Account Number">
                  <input
                    type="text"
                    value={form.bank_account_number}
                    onChange={(e) => set('bank_account_number', e.target.value)}
                    placeholder="62012345678"
                    className={inputClass}
                  />
                </Field>

                <Field label="Branch Code">
                  <input
                    type="text"
                    value={form.bank_branch_code}
                    onChange={(e) => set('bank_branch_code', e.target.value)}
                    placeholder="250655"
                    className={inputClass}
                  />
                </Field>
              </div>
            </div>

            {/* Additional */}
            <div className="rounded-lg border border-[var(--ff-border-primary)] bg-[var(--ff-surface-primary)] p-6 mb-6">
              <h2 className="text-sm font-semibold text-[var(--ff-text-primary)] uppercase tracking-wide mb-4">
                Additional
              </h2>
              <div className="grid grid-cols-1 gap-4">
                <Field label="Notes">
                  <textarea
                    value={form.notes}
                    onChange={(e) => set('notes', e.target.value)}
                    rows={3}
                    placeholder="Internal notes about this supplier..."
                    className={textareaClass}
                  />
                </Field>

                <div className="flex items-center gap-3">
                  <button
                    type="button"
                    role="switch"
                    aria-checked={form.is_active}
                    onClick={() => set('is_active', !form.is_active)}
                    className={`relative inline-flex h-5 w-9 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors focus:outline-none ${
                      form.is_active ? 'bg-emerald-600' : 'bg-[var(--ff-bg-tertiary)]'
                    }`}
                  >
                    <span
                      className={`inline-block h-4 w-4 rounded-full bg-white shadow ring-0 transition-transform ${
                        form.is_active ? 'translate-x-4' : 'translate-x-0'
                      }`}
                    />
                  </button>
                  <span className="text-sm text-[var(--ff-text-secondary)]">Active supplier</span>
                </div>
              </div>
            </div>

            {/* Actions */}
            <div className="flex items-center justify-end gap-3">
              <Link
                href="/accounting/suppliers"
                className="px-4 py-2 rounded-lg border border-[var(--ff-border-primary)] text-[var(--ff-text-secondary)] hover:text-[var(--ff-text-primary)] hover:bg-[var(--ff-bg-tertiary)] text-sm font-medium transition-colors"
              >
                Cancel
              </Link>
              <button
                type="submit"
                disabled={isSubmitting}
                className="flex items-center gap-2 px-5 py-2 rounded-lg bg-emerald-600 hover:bg-emerald-700 disabled:opacity-60 disabled:cursor-not-allowed text-white text-sm font-medium transition-colors"
              >
                {isSubmitting ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <Save className="h-4 w-4" />
                )}
                {isSubmitting ? 'Saving...' : 'Save Supplier'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </AppLayout>
  );
}

