/**
 * New Supplier Form Page
 * Creates a new supplier record via POST /api/accounting/suppliers-list.
 * Route: /accounting/suppliers/new
 */

import { useState } from 'react';
import { useRouter } from 'next/router';
import { AppLayout } from '@/components/layout/AppLayout';
import { Truck, Loader2, ArrowLeft, Save } from 'lucide-react';
import Link from 'next/link';
import { toast } from 'react-hot-toast';

interface SupplierFormData {
  name: string;
  company_name: string;
  email: string;
  phone: string;
  vat_number: string;
  registration_number: string;
  contact_person: string;
  payment_terms: string;
  address: string;
  category: string;
  notes: string;
  is_active: boolean;
  // Bank details
  bank_name: string;
  bank_account_number: string;
  bank_branch_code: string;
  bank_account_type: string;
}

const INITIAL_FORM: SupplierFormData = {
  name: '',
  company_name: '',
  email: '',
  phone: '',
  vat_number: '',
  registration_number: '',
  contact_person: '',
  payment_terms: '30',
  address: '',
  category: '',
  notes: '',
  is_active: true,
  bank_name: '',
  bank_account_number: '',
  bank_branch_code: '',
  bank_account_type: 'current',
};

const ACCOUNT_TYPES = [
  { value: 'current', label: 'Current / Cheque' },
  { value: 'savings', label: 'Savings' },
  { value: 'transmission', label: 'Transmission' },
];

const SUPPLIER_CATEGORIES = [
  'Materials',
  'Services',
  'Equipment',
  'Subcontractor',
  'Utilities',
  'Professional Services',
  'Logistics',
  'Other',
];

interface FieldProps {
  label: string;
  required?: boolean;
  children: React.ReactNode;
  hint?: string;
}

function Field({ label, required, children, hint }: FieldProps) {
  return (
    <div>
      <label className="block text-sm font-medium text-[var(--ff-text-secondary)] mb-1">
        {label}
        {required && <span className="text-red-400 ml-1">*</span>}
      </label>
      {children}
      {hint && <p className="mt-1 text-xs text-[var(--ff-text-tertiary)]">{hint}</p>}
    </div>
  );
}

const inputClass =
  'w-full px-3 py-2 rounded-lg bg-[var(--ff-bg-tertiary)] border border-[var(--ff-border-primary)] text-[var(--ff-text-primary)] placeholder:text-[var(--ff-text-tertiary)] text-sm focus:outline-none focus:ring-1 focus:ring-emerald-500';

const textareaClass = `${inputClass} resize-none`;
const selectClass = `${inputClass} cursor-pointer`;

