                  )}
                </Field>

                <div className="sm:col-span-2">
                  <Field label="Physical Address">
                    <textarea
                      value={form.address}
                      onChange={(e) => set('address', e.target.value)}
                      rows={3}
                      placeholder="Street address, city, postal code"
                      className={textareaClass}
                    />
                  </Field>
                </div>
              </div>
            </div>

            {/* Bank Details */}
            <div className="rounded-lg border border-[var(--ff-border-primary)] bg-[var(--ff-surface-primary)] p-6 mb-6">
              <h2 className="text-sm font-semibold text-[var(--ff-text-primary)] uppercase tracking-wide mb-1">
                Bank Details
              </h2>
              <p className="text-xs text-[var(--ff-text-tertiary)] mb-4">
