  label: string;
  required?: boolean;
  children: React.ReactNode;
  hint?: string;
}

function Field({ label, required, children, hint }: FieldProps) {
  return (
    <div>
      <label className="block text-sm font-medium text-[var(--ff-text-secondary)] mb-1">
        {label}
        {required && <span className="text-red-400 ml-1">*</span>}
      </label>
      {children}
      {hint && <p className="mt-1 text-xs text-[var(--ff-text-tertiary)]">{hint}</p>}
    </div>
  );
}

const inputClass =
  'w-full px-3 py-2 rounded-lg bg-[var(--ff-bg-tertiary)] border border-[var(--ff-border-primary)] text-[var(--ff-text-primary)] placeholder:text-[var(--ff-text-tertiary)] text-sm focus:outline-none focus:ring-1 focus:ring-emerald-500';

const textareaClass = `${inputClass} resize-none`;

export default function NewCustomerPage() {
  const router = useRouter();
  const [form, setForm] = useState<CustomerFormData>(INITIAL_FORM);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [fieldErrors, setFieldErrors] = useState<Partial<Record<keyof CustomerFormData, string>>>({});

  function set<K extends keyof CustomerFormData>(key: K, value: CustomerFormData[K]) {
    setForm((prev) => ({ ...prev, [key]: value }));
    setFieldErrors((prev) => ({ ...prev, [key]: undefined }));
  }

  function validate(): boolean {
    const errors: Partial<Record<keyof CustomerFormData, string>> = {};
    if (!form.name.trim()) errors.name = 'Customer name is required';
    if (form.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) {
      errors.email = 'Enter a valid email address';
    }
    if (form.payment_terms && isNaN(Number(form.payment_terms))) {
      errors.payment_terms = 'Must be a number';
    }
    if (form.credit_limit && isNaN(Number(form.credit_limit))) {
      errors.credit_limit = 'Must be a number';
    }
    setFieldErrors(errors);
    return Object.keys(errors).length === 0;
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!validate()) return;

    setIsSubmitting(true);
    try {
      const payload = {
        ...form,
        payment_terms: form.payment_terms ? Number(form.payment_terms) : 30,
        credit_limit: form.credit_limit ? Number(form.credit_limit) : null,
      };

      const res = await fetch('/api/accounting/customers', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      const json = await res.json();

      if (!res.ok) {
        throw new Error(json.error?.message ?? `HTTP ${res.status}`);
      }

      toast.success('Customer created successfully');
      await router.push('/accounting/customers');
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Failed to create customer';
      toast.error(message);
    } finally {
      setIsSubmitting(false);
    }
  }

  return (
    <AppLayout>
      <div className="min-h-screen bg-[var(--ff-bg-primary)]">
        {/* Header */}
        <div className="border-b border-[var(--ff-border-primary)] bg-[var(--ff-bg-secondary)]">
          <div className="px-6 py-4 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <Link
                href="/accounting/customers"
                className="p-1.5 rounded-lg hover:bg-[var(--ff-bg-tertiary)] text-[var(--ff-text-secondary)] transition-colors"
              >
                <ArrowLeft className="h-5 w-5" />
              </Link>
              <div className="p-2 rounded-lg bg-emerald-500/10">
                <Users className="h-6 w-6 text-emerald-500" />
              </div>
              <div>
                <h1 className="text-xl font-semibold text-[var(--ff-text-primary)]">New Customer</h1>
                <p className="text-sm text-[var(--ff-text-secondary)]">Add a new customer account</p>
              </div>
            </div>
          </div>
        </div>

        <div className="p-6 max-w-3xl">
          <form onSubmit={handleSubmit} noValidate>
            {/* Basic Information */}
            <div className="rounded-lg border border-[var(--ff-border-primary)] bg-[var(--ff-surface-primary)] p-6 mb-6">
              <h2 className="text-sm font-semibold text-[var(--ff-text-primary)] uppercase tracking-wide mb-4">
                Basic Information
              </h2>
              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
                <div className="sm:col-span-2">
                  <Field label="Customer Name" required>
                    <input
                      type="text"
                      value={form.name}
                      onChange={(e) => set('name', e.target.value)}
                      placeholder="e.g. Acme Corporation"
                      className={inputClass}
                      autoFocus
                    />
                    {fieldErrors.name && (
                      <p className="mt-1 text-xs text-red-400">{fieldErrors.name}</p>
                    )}
                  </Field>
                </div>

                <Field label="Email Address">
                  <input
                    type="email"
                    value={form.email}
                    onChange={(e) => set('email', e.target.value)}
                    placeholder="billing@example.com"
                    className={inputClass}
                  />
                  {fieldErrors.email && (
                    <p className="mt-1 text-xs text-red-400">{fieldErrors.email}</p>
                  )}
                </Field>

                <Field label="Phone Number">
                  <input
                    type="tel"
                    value={form.phone}
                    onChange={(e) => set('phone', e.target.value)}
                    placeholder="+27 11 000 0000"
                    className={inputClass}
                  />
                </Field>

                <Field label="Contact Person">
                  <input
                    type="text"
                    value={form.contact_person}
                    onChange={(e) => set('contact_person', e.target.value)}
                    placeholder="John Smith"
                    className={inputClass}
                  />
                </Field>

                <Field label="VAT Number">
                  <input
                    type="text"
                    value={form.vat_number}
                    onChange={(e) => set('vat_number', e.target.value)}
                    placeholder="4123456789"
                    className={inputClass}
                  />
                </Field>

                <Field label="Registration Number">
                  <input
                    type="text"
                    value={form.registration_number}
                    onChange={(e) => set('registration_number', e.target.value)}
                    placeholder="2020/123456/07"
                    className={inputClass}
                  />
                </Field>
              </div>
            </div>

            {/* Billing Settings */}
            <div className="rounded-lg border border-[var(--ff-border-primary)] bg-[var(--ff-surface-primary)] p-6 mb-6">
              <h2 className="text-sm font-semibold text-[var(--ff-text-primary)] uppercase tracking-wide mb-4">
                Billing Settings
              </h2>
              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
                <Field label="Payment Terms" hint="Number of days until payment is due">
                  <input
                    type="number"
                    min="0"
                    value={form.payment_terms}
                    onChange={(e) => set('payment_terms', e.target.value)}
                    className={inputClass}
                  />
                  {fieldErrors.payment_terms && (
                    <p className="mt-1 text-xs text-red-400">{fieldErrors.payment_terms}</p>
                  )}
                </Field>

                <Field label="Credit Limit" hint="Leave blank for no limit">
                  <input
                    type="number"
                    min="0"
                    step="0.01"
                    value={form.credit_limit}
                    onChange={(e) => set('credit_limit', e.target.value)}
                    placeholder="0.00"
                    className={inputClass}
                  />
                  {fieldErrors.credit_limit && (
                    <p className="mt-1 text-xs text-red-400">{fieldErrors.credit_limit}</p>
                  )}
                </Field>

                <div className="sm:col-span-2">
                  <Field label="Billing Address">
                    <textarea
                      value={form.billing_address}
                      onChange={(e) => set('billing_address', e.target.value)}
                      rows={3}
                      placeholder="Street address, city, postal code"
                      className={textareaClass}
                    />
                  </Field>
                </div>

                <div className="sm:col-span-2">
                  <Field label="Shipping Address" hint="Leave blank if same as billing address">
                    <textarea
                      value={form.shipping_address}
                      onChange={(e) => set('shipping_address', e.target.value)}
                      rows={3}
                      placeholder="Street address, city, postal code"
                      className={textareaClass}
                    />
                  </Field>
                </div>
              </div>
            </div>

            {/* Additional */}
            <div className="rounded-lg border border-[var(--ff-border-primary)] bg-[var(--ff-surface-primary)] p-6 mb-6">
              <h2 className="text-sm font-semibold text-[var(--ff-text-primary)] uppercase tracking-wide mb-4">
                Additional
              </h2>
              <div className="grid grid-cols-1 gap-4">
                <Field label="Notes">
                  <textarea
                    value={form.notes}
                    onChange={(e) => set('notes', e.target.value)}
                    rows={3}
                    placeholder="Internal notes about this customer..."
                    className={textareaClass}
                  />
                </Field>

                <div className="flex items-center gap-3">
                  <button
                    type="button"
                    role="switch"
                    aria-checked={form.is_active}
                    onClick={() => set('is_active', !form.is_active)}
                    className={`relative inline-flex h-5 w-9 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors focus:outline-none ${
                      form.is_active ? 'bg-emerald-600' : 'bg-[var(--ff-bg-tertiary)]'
                    }`}
                  >
                    <span
                      className={`inline-block h-4 w-4 rounded-full bg-white shadow ring-0 transition-transform ${
                        form.is_active ? 'translate-x-4' : 'translate-x-0'
                      }`}
                    />
                  </button>
                  <span className="text-sm text-[var(--ff-text-secondary)]">Active customer</span>
                </div>
              </div>
            </div>

            {/* Actions */}
            <div className="flex items-center justify-end gap-3">
              <Link
                href="/accounting/customers"
                className="px-4 py-2 rounded-lg border border-[var(--ff-border-primary)] text-[var(--ff-text-secondary)] hover:text-[var(--ff-text-primary)] hover:bg-[var(--ff-bg-tertiary)] text-sm font-medium transition-colors"
              >
                Cancel
              </Link>
              <button
                type="submit"
                disabled={isSubmitting}
                className="flex items-center gap-2 px-5 py-2 rounded-lg bg-emerald-600 hover:bg-emerald-700 disabled:opacity-60 disabled:cursor-not-allowed text-white text-sm font-medium transition-colors"
              >
                {isSubmitting ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <Save className="h-4 w-4" />
                )}
                {isSubmitting ? 'Saving...' : 'Save Customer'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </AppLayout>
  );
}

